import{_ as p,o as t,c as e,aj as i}from"./chunks/framework.DNJ2HNkG.js";const E=JSON.parse('{"title":"家用PCDN指南","description":"","frontmatter":{"title":"家用PCDN指南","date":"2023-03-21T09:52:19.000Z","category":"Home","tags":["Home"]},"headers":[],"relativePath":"posts/家用PCDN指南.md","filePath":"posts/家用PCDN指南.md","lastUpdated":1783047625000}'),r={name:"posts/家用PCDN指南.md"};function n(o,a,s,l,h,c){return t(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="_0x01-背景" tabindex="-1">0x01 背景 <a class="header-anchor" href="#_0x01-背景" aria-label="Permalink to &quot;0x01 背景&quot;">​</a></h1><p>大家作为IT人，网络是刚需，一般家里都300M-1000M的宽带，很多还带公网IP，日常大家也就用它下载，看看视频看看聚，下载点东西，玩玩游戏，至于上传，一般也就微信/钉钉传下文件，传个网盘。至于玩PT的人还是少数。</p><p>但实际上，在国际上宽带费用也算Top的兔国，还有一些小众玩法，比如这里提到的PCDN。</p><h1 id="_0x02-什么是pcdn" tabindex="-1">0x02 什么是PCDN <a class="header-anchor" href="#_0x02-什么是pcdn" aria-label="Permalink to &quot;0x02 什么是PCDN&quot;">​</a></h1><p>可以先问问chatgpt，在我看来pcdn也可以理解为personal cdn，用个人的家用宽带做cdn节点。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679364276720.png" alt="chatgpt"></p><p>兔国的宽带太贵了，具体可以参照阿里云/腾讯云买vps时候选择宽带，加一点要加价多少。所以很多视频app、网站，为了更好的用户体验，需要采购诸多CDN服务，来对内容做加速，在这个大背景下，pcdn应运而生。</p><p>个人用户的宽带其实很早就有商用案例， 比如代理盒子，爬虫必备的代理IP池需要很多ip，以前在360时候，就可以申领一个小盒子插在家里的宽带上，可以每月申请一笔补贴，其实就是借用个人宽带做ip代理，现在很多app、边缘计算盒子、sd-wan盒子、游戏加速盒子，都在偷着摸着干这种事情，而这些ip、设备标识，在DAU/MAU作弊、网络水军、薅羊毛、爬虫、广告点击等领域，有着非常非常非常广泛的用途。</p><p>比如说，很多app都在偷偷摸摸干着，就不点名了，很多视频APP在你看完缓存完之后，会利用p2p技术给其他用户做分享，偷偷占用你的硬盘缓存和上行带宽，用防火墙或者流量分析设备抓取下就可以看到了。</p><p>这时候，就有了明面上的pcdn服务公司诞生，出现了各种“跑分”盒子，早年斐讯搞得挖矿盒子其实套路不对，如果把挖矿换成跑分，可能就不会凉的这么快，后来的继任者也是在这基础上发展起来的，比如迅雷的网心云、点心云、京东云、甜糖、猕猴桃、超点云等等</p><p>这些厂商都要求用户采购他们的盒子设备，或者部署虚拟机、app应用，然后提供硬盘缓存、宽带等接入，再在后台做cdn资源分配，之后根据质量和流量给用户付费。</p><p>下面2张图是我家雅典娜和点心云的流量监控，可以看到其实就是给各大视频、网站做分流。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679364464152.png" alt="雅典娜流量"></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679364545800.png" alt="点心流量"></p><h1 id="_0x03-怎么玩pcdn" tabindex="-1">0x03 怎么玩PCDN <a class="header-anchor" href="#_0x03-怎么玩pcdn" aria-label="Permalink to &quot;0x03 怎么玩PCDN&quot;">​</a></h1><p>在smzdm等网站上，搜pcdn、雅典娜、点心云等关键字能搜到非常多的文章，有很多攻略，有兴趣的可以搜搜看。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679366093932.png" alt="smzdm"> 我是从去年5月开始入坑跑pcdn的，一开始是京东云雅典娜，后来试了下点心和网心，这里就简单晒2张图，基本上去年在jd买米面油数码就没咋花钱，能用礼品卡、京豆的太多了，而点心云则是直接给现金。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679366614184.png" alt="京豆"></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679366456544.png" alt="jd礼品卡"></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679366486533.png" alt="点心云举例"></p><p>这里我就简单讲下怎么玩PCDN，一般来说，PCDN的收入能覆盖家里的水电气网费用开销，以我举例，750+350买了6台雅典娜+SSD，7个月后700+300一台出手。</p><ol><li>平均收益30/天，年收入：35*365=10950</li><li>电信宽带融合套餐：299*12=3588</li><li>水电气费：4669</li><li>设备折旧：100*6=600</li></ol><p>对于不富裕的我，PCDN的收入还是可以的。</p><h2 id="_0x31-准备工作" tabindex="-1">0x31 准备工作 <a class="header-anchor" href="#_0x31-准备工作" aria-label="Permalink to &quot;0x31 准备工作&quot;">​</a></h2><p>先看下自家的带宽的参数：</p><h4 id="_1-是电信-移动-联通中的哪一家" tabindex="-1">1. 是电信/移动/联通中的哪一家? <a class="header-anchor" href="#_1-是电信-移动-联通中的哪一家" aria-label="Permalink to &quot;1. 是电信/移动/联通中的哪一家?&quot;">​</a></h4><p>一般来说，南电信，北联通，这两家的宽带质量比较高，宽带稳定，移动没有自己的骨干网，一般都是租用电信或者联通的线路，至于鹏博士、长城宽带等杂七杂八的宽带就不用考虑了，如果家里是御三家的，基本可以确定能跑。</p><h4 id="_2-下行带宽多少-上行带宽多少" tabindex="-1">2. 下行带宽多少，上行带宽多少 <a class="header-anchor" href="#_2-下行带宽多少-上行带宽多少" aria-label="Permalink to &quot;2. 下行带宽多少，上行带宽多少&quot;">​</a></h4><p>这个一般就是办理的是什么宽带，比如1000M宽带都是指下行，也就是下载1000Mbit，也就是下载1000/8=125M/S的速度，但PCDN要的是上行，也就是上传速度，毕竟你的缓存别的用户要用，需要从你的设备里上传出去给他们，而上行，在兔国非常昂贵！</p><p>以杭州电信为例，200M/300M/500M/1000M宽带，资费隔不少，但上行默认都是30M，也就是30/8=3.75M/S的上传速度，而100M/200M的上行套餐，可遇而不可求，曾经100M上行的直播套餐，也从299涨到了599。而上行，也决定了PCDN的收益有多少，理论上上行越高，收益越高，所以也有很多人通过多拉宽带的方式来提高上行，30M的宽带拉10条就有300M了。</p><p>还有上下行对等的宽带，比如上行下行都是100M的那种，但这属于企业宽带，自费非常非常贵，一般是企业拉来做服务的，可以不是部署服务器，给固定的公网IP的那种，这种宽带用来跑PCDN得不偿失。</p><h4 id="_3-有没有公网ip" tabindex="-1">3. 有没有公网IP <a class="header-anchor" href="#_3-有没有公网ip" aria-label="Permalink to &quot;3. 有没有公网IP&quot;">​</a></h4><p>因为兔国的公网IP资源非常紧张，所以公网IP一直都很稀缺，能否给公网IP一般看当地运营商政策，比如杭州电信都是直接给，江西电信是加钱或者升级套餐才给，有些地方也可以通过投诉给公网IP，具体要看当地运营商政策，或者网上找找其他网友的做法。</p><p>当然，家用宽带的公网IP，一般也仅仅只是方便个人用户做家庭资源访问或者分享的，比如家里有个nas，或者从外地访问家里的网络。家用宽带的公网IP一般每48/72小时会变一次，其实是光猫的adsl pppoe连接会超时重连，然后重新分配IP，这些公网ip的21/22/80/443/8080等常用端口都禁用，防止个人用户用宽带开网站服务。当然，这都有解法，一般搞个ddns就可以了，在光猫或者家里设备里跑个ddns服务，自动将域名解析成出口IP，再做端口映射或者反代，都可以。</p><p>在PCDN上，公网ip意味着用户可以通过ip访问你缓存的资源，链路短质量高，比方说《狂飙》正火的时候，全国有1亿人在app用上看1080p，想想这得多大带宽？光靠爱奇艺自己肯定扛不住，这时候杭州的你家PCDN设备上有缓存，杭州的我看的时候，直接访问你家公网IP，看你的缓存，延迟低效果好，这就是pcdn的价值。</p><p>如果没有公网IP，比如杭州移动，一般都是大内网，不给公网IP，但用移动宽带的人也不少，pcdn服务商通过后台，判断出都是移动的，然后给用户app发索引表，直接访问你的内网ip，也可以加速，如果不是同区域移动内网的用户，就基本没法访问，udp打洞的成功率不保险，所以，没有公网IP的话，pcdn收入一般比有公网IP的低，但这也不是绝对，如果你同区域的移动宽带用户多，切有很多刷视频的达人，那你就happy了，可能比那些有公网IP的人收益还高。</p><h4 id="_4-能否多拨" tabindex="-1">4. 能否多拨 <a class="header-anchor" href="#_4-能否多拨" aria-label="Permalink to &quot;4. 能否多拨&quot;">​</a></h4><p>国内很多运营商宽带都允许多拨，也就是说用你的宽带账密5条线路同时pppoe拨号，会有可能同时拨上，获取5个IP，而且有些运营商会存在宽带冗余，多拨下行不叠加，但上行会叠加2倍，也就是说，30M上行，多拨会得到60M，单条虽然限制了30M，但多拨加起来会到60M，这时候，PCDN就相当于有翻倍的收入。</p><p>但多拨其实不是非常稳定，首先必须同时拨号，这就导致大部分支持多拨的家用乃至企业路由器都无法多拨成功，LEDE/ROS测试都多拨最多2拨，且成功率很低，一般都不是并发多拨，目前测试ikuai多拨是比较ok的，但也要经常检查，因为断开后自动重拨一般都无法多拨成功。</p><p>但总体上来说，这种白嫖的上行宽带，不要再有更高预期了，不是么？</p><h4 id="_5-是否影响日常使用" tabindex="-1">5. 是否影响日常使用 <a class="header-anchor" href="#_5-是否影响日常使用" aria-label="Permalink to &quot;5. 是否影响日常使用&quot;">​</a></h4><p>PCDN会经常更新热门缓存，所以除了吃上传，也会吃下载，但一般不影响正常使用，可如果玩对延迟非常敏感的游戏，比如吃鸡、王者荣耀、LOL，在高峰时段可能会有影响，但影响有多大，也需要看实际测试。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679370028158.png" alt="流量监控"></p><h4 id="_6-投入多大" tabindex="-1">6. 投入多大 <a class="header-anchor" href="#_6-投入多大" aria-label="Permalink to &quot;6. 投入多大&quot;">​</a></h4><p>如果只是傻瓜式简单玩玩，那我推荐搞个京东云雅典娜汰换掉现在的wifi路由就可以了，128G版本在jd上大概800块，海鲜市场600-700，激活日期越新鲜越好，电子产品毕竟有使用寿命。再在jd搞个500G以上的ssd配个usb3.0的硬盘盒挂上做缓存，最好搞1T或者2T的，现在硬盘便宜，回头雅典娜卖了回血，ssd还能自己用。</p><p>雅典娜作为wifi路由非常不错，三频AX6600，2.5G网口，颜值也还不错，支持mesh，自用外加跑分给积分，可以直接换京豆或者京东卡。</p><p>具体玩法smzdm上有很多。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679370586300.png" alt="京东云雅典娜"></p><p>如果想玩得happy点，那就上软路由，上面跑ikuai多拨，再挂个LEDE旁路由做全屋科学上网，搞个黑群晖/qnap管理照片、文件，还可以搞个虚拟机跑docker，有时间有精力，能玩的花活儿很多。</p><h2 id="_0x32-设备采购" tabindex="-1">0x32 设备采购 <a class="header-anchor" href="#_0x32-设备采购" aria-label="Permalink to &quot;0x32 设备采购&quot;">​</a></h2><p>首先需要准备设备，根据我自己和网友的经验，电信网络，一般单30M上行能带来4-5块收入，多拨都能到8-10块，100M上行多拨能到30-40块，所以，根据家里宽带情况来做准备，也可以考虑升级下带宽，或者拉二宽，基本上是不会亏本的。</p><p>这里就举例几个常用的方案。</p><h4 id="_1-京东云路由" tabindex="-1">1. 京东云路由 <a class="header-anchor" href="#_1-京东云路由" aria-label="Permalink to &quot;1. 京东云路由&quot;">​</a></h4><p>如果是京东云的，直接在jd/pdd下单就行，如果不怕海鲜市场水深，也可以买二手。设备种类很多，wifi路由的参数也有很多，具体可以看smzdm，记住一个原则，一分钱一分货，配置高，扩展好的可玩性高。wifi路由其实是耗材，这几年技术进步快，wifi6/wifi6e/wifi7也就这几年时间，加上现在宽带提速快，家用联网设备终端多，要想用户体验好，这里面最好不要省钱。</p><p>如果家里是大豪宅，可以考虑ac+ap或者mesh，多部署几个wifi路由，不过京东云的wifi路由的mesh子路由不好跑分。此外，京东云APP里还可以设置积分模式，极限积分就是纯跑分，调度优先级最高，wifi功能都会关掉，还有其他几种模式，按需选用即可。</p><p>另外，京东云的坐享其成计划也还行，限速后打卡，基本上一年后都可以白嫖。大部分家用宽带和雅典娜的组合都能在半年到一年时间回本，然后可以卖掉路由或者继续跑分。</p><p>京东云也是有调度机制的，不同型号有不同的上限，比如雅典娜上限888，不过现在新的资料介绍里都基本没有这个了，这些资本家本质都是压榨，吃尽量多的带宽，付尽量少的钱。再就是缓存越大，命中率越高，积分越多，所以外挂的硬盘越大越好。</p><p><strong>还有个小技巧，外挂硬盘其实就是ext4分区的硬盘，要更换硬盘或者复制缓存，直接在linux下格式化新盘，将老盘数据拷过去就行。京东云会每天删除旧的增加新的缓存，但有时候调度很慢，可以考虑每半年或者1年主动格式化一次缓存</strong></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679372624438.png" alt="京东云"></p><h4 id="_2-点心云" tabindex="-1">2. 点心云 <a class="header-anchor" href="#_2-点心云" aria-label="Permalink to &quot;2. 点心云&quot;">​</a></h4><p>点心云没有专用设备，直接用物理机装系统或者或者虚拟机，盒子、树莓派之类的跑。</p><p>x86的其实就是一个centos的系统里面跑了点心的应用，内核很老，太新的硬件，比如2.5g网卡不支持。</p><p>点心的业务很简陋，客服支持也是qq群形式，但目前还算大方，给钱多，这也是我现在主跑之一。</p><p>另外给个小技巧，虚拟机分配内存必须8G以上，硬盘必须500G以上。开发人员很简单的就按内存大小判断设备配置高低，配置越高调度越多，所以我之前跑分一直很低，直到一个朋友给了这个提示，改成8G钱就多了。而且，同配置下，物理机比虚拟机多，16G比8G多。</p><p><strong>经过1个月对比测试，建议用7代i5以上的低压U工控主板或者小主机，TDP 15W，功耗非常低，然后用esxi跑虚拟机，内存越大越好，比如64G内存，SSD可以用4T/8T的sata ssd，或者多装几块2T的SSD，现在内存和SSD越来越便宜。单个虚拟机内存8G以上，硬盘500G以上，每个虚拟机用ikuai多拨分配线路，每条线路一个虚拟机。</strong></p><p>如果用物理机的话，建议TDP 10W的J4125一类，性能要好，功耗要低，不建议N5105，发热严重且配i225/i226有断流bug，pcdn对网络稳定度有要求。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679374845941.png" alt="点心设备"></p><p>点心每周五工作时间可以提现，直接到银行卡。收益榜单在官方app的首页可以看到，一天一两百，一个月躺赚小6K。但arm的就比x86的低很多，点心因为现在跑的人不多，所以给钱很大方，目前还是红利期。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679375521371.png" alt="点心app首页收益榜单"></p><h4 id="_3-网心云" tabindex="-1">3. 网心云 <a class="header-anchor" href="#_3-网心云" aria-label="Permalink to &quot;3. 网心云&quot;">​</a></h4><p>官网：<a href="https://www.onethingcloud.com/" target="_blank" rel="noreferrer">https://www.onethingcloud.com/</a></p><p>网心云是迅雷旗下的，玩法很多，可以买他们出的盒子“赚钱宝”，优点是配置傻瓜，调度可能优先级高，但这些盒子如果不跑pcdn就没啥用，性价比一般。x86盒子虽然可以干其他的，但性价比太低了。再就是群晖等nas里面迅雷app可以通过插件跑网心，但给的钱很少，跑的意义不大。</p><p>网心也支持虚拟机、win直接跑程序、三方盒子刷机、树莓派、docker、手机app，本质上其实就是一个客户端应用，能缓存数据，能把服务开放出去，能接受远程调度指令就行。网心的x86需要1块钱买码，但这投入基本可以忽略吧。</p><p>另外，还有个定向邀请服务，就是如果带宽够大硬盘够多，这种一般都是做cdn的人赚外快搞的，这种基本上都是搞服务器跑。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679374645017.png" alt="网心设备"></p><p>点心和网心跑过对比测试，市面上跑网心的人更多，从网心app首页收益排行榜可以看到，一天五六百，一个月一万多，收入非常可观。但同样的，因为跑的人多，所以相比点心就要抠很多，吃得多给的少，跑了一段时间后网心我就放弃了。</p><p>网心每周二工作时间体现。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679375655247.png" alt="网心收益榜单"></p><h4 id="_4-其他" tabindex="-1">4. 其他 <a class="header-anchor" href="#_4-其他" aria-label="Permalink to &quot;4. 其他&quot;">​</a></h4><p>其他还有甜糖、猕猴桃等小厂，跑的门槛也很低，但应用也很简陋，给钱也少，所以基本不用考虑。</p><h2 id="_0x33-网络部署" tabindex="-1">0x33 网络部署 <a class="header-anchor" href="#_0x33-网络部署" aria-label="Permalink to &quot;0x33 网络部署&quot;">​</a></h2><p>一般来说，在不专业搞pcdn的前提下，pcdn只是家用网络设备的一个，所以用点心网心拨号基本不用考虑。如果只是玩单一雅典娜，那可以考虑用雅典娜拨号，这样比较简单，因为运营商送的光猫性能都很差，用光猫拨号做nat转换，性能损失很大，且很多光猫默认不开启upnp，严重影响pcdn收益。</p><p>京东云路由到手以后，可以先打运营商客服，要一下你的宽带账号密码，然后要求光猫改桥接，再把路由器wan口接到光猫千兆口上，然后登录进路由器，设置宽带连接方式为拨号，输入宽带账密，就可以了。</p><p>如果实在不想搞，一定要用光猫拨号，那找装维人员问一下光猫的超级管理密码，登录后将upnp打开。</p><p>如果家里宽带1000M以上，如果送的猫太差，建议自行更换性能更好的华为猫、中兴猫或者猫棒、2.5G vsol猫等，具体可以看我的系列文章：</p><p><a href="https://blog.white-alone.com/%E5%AE%B6%E5%BA%AD%E7%BD%91%E7%BB%9C%E5%8D%87%E7%BA%A7%E6%8C%87%E5%8D%97%E3%80%90%E4%B8%80%E3%80%91/" target="_blank" rel="noreferrer">《家庭网络升级指南【一】》</a></p><p>如果打算搞多拨，那就需要一台J4125/8G/32G/2千兆口以上的<a href="https://blog.white-alone.com/%E8%BD%AF%E8%B7%AF%E7%94%B1%E9%85%8D%E7%BD%AE/" target="_blank" rel="noreferrer">软路由</a>，性能如果很低，就直接裸跑ikuai，很高就跑虚拟化，多开几个虚拟机。</p><p>现在工控厂商卷入软路由赛道，白菜价，可以搞一个。系统是PVE还是ESXi按自己习惯搞，我更喜欢ESXi，CPU、磁盘和网络性能损失都比pve小。</p><p>ESXi里面新建几个虚拟机，第一个是ikuai，作为主路由，分配4线程以上cpu，内存4G，硬盘16G足够，网络把几个网卡都挂进去，或者直通进去也可以。</p><p>按正常配置后，在wan里设置多拨，如果不确定自家宽带是否支持多拨，可以直接用ikuai测试下。但需要注意的是，<strong>多拨定期会掉，所以最好定期登录检查下，如果多拨失败，可以断开所有拨号，等待3-5分钟再拨，一般都能拨上多个。</strong></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679376673715.png" alt="ikuai多拨"></p><p><strong>一定记得打开upnp，这点非常重要，因为pcdn设备的服务器端口要通过upnp到公网或者运营商大内网。</strong></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679377929105.png" alt="ikuai的upnp"></p><p>之后在lan口，将pcdn设备都挂上，不管是虚拟机还是物理机，都会分配ip，再将设备IP在DHCP里设置成静态IP，防止ip变化，然后再根据ip和拨号上的线路进行分流。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E7%94%A8PCDN%E6%8C%87%E5%8D%97/1679376755565.png" alt="分流设置"></p><p>如果软路由性能很高，可以考虑在sata口装上大容量ssd，或者usb外挂ssd，然后直接在软路由里跑pcdn，all in one！</p><p>另外如果有科学上网需求，可以在跑个lede的旁路由虚拟机，将pcdn之外的设备网关设置成旁路由ip，这样家里手机电脑电视盒子，就可以愉快的看谷歌奈飞油管迪士尼了。</p><p>之后就可以愉快的坐收pcdn的收益了，躺赚！</p><h1 id="_0x04-结语" tabindex="-1">0x04 结语 <a class="header-anchor" href="#_0x04-结语" aria-label="Permalink to &quot;0x04 结语&quot;">​</a></h1><p>pcdn是一种特殊应用，将闲置带宽贡献出来赚取外快的方式，家里有古董台式、笔记本、手机也可以用来跑，但从功耗电费角度上，还是建议用低功耗x86设备来跑。</p><p>此外，某些地区，比如山东、广东、上海的某些区域会打击pcdn活动，因为这种也勉强算是提供网络服务，所以，估算下投入和产出，小玩即可，用通用硬件，不玩了随时可以卖，投入不大，随时可以下车。</p><p><strong>最后，从PCDN市场角度，玩得人越多，厂商给的钱越少，物以稀为贵，所以，虽然网上能搜到很多类似的，但本文不适合大范围传播，大家自己玩玩就好，在物价飞涨的今天，补贴点家用。</strong></p>',102)])])}const m=p(r,[["render",n]]);export{E as __pageData,m as default};
